window.BIBLE["James"] = {"1":{"chapter":"1","title":"COUNT IT ALL JOY","verses":{"1":{"text":"James, a servant of God and of the Lord Jesus Christ, to the twelve tribes which are scattered abroad, greeting.","ref":"James 1:1","synthesized":"James, a servant of God and of the Lord Jesus Christ,  To the twelve tribes of the Dispersion:  Greetings.","sources":{"KJV":{"text":"James, a servant of God and of the Lord Jesus Christ, to the twelve tribes which are scattered abroad, greeting."},"BSB":{"text":"James, a servant of God and of the Lord Jesus Christ,  To the twelve tribes of the Dispersion:  Greetings."}},"definableWords":["servant","God","Lord","Christ"],"peopleInVerse":["James","Jesus"],"kingdomLens":"'My brethren, count it all joy when ye fall into divers temptations; Knowing this, that the trying of your faith worketh patience' (1:2-3). Trials produce maturity. Lack wisdom? Ask God. The rich man fades like a flower. Every good gift comes from above. Be swift to hear, slow to speak, slow to wrath. Be doers, not just hearers. Pure religion: visit orphans and widows in their affliction.","cultural":{"title":"Count it all joy","detail":"James (the Lord's brother) was nicknamed 'Camel Knees' by tradition (Hegesippus) for the calluses on his knees from constant prayer. Murdered by stoning around AD 62 — Josephus records his death in Antiquities XX.9.1.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"My brethren, count it all joy when ye fall into divers temptations;","ref":"James 1:2","synthesized":"Consider it pure joy, my brothers, when you encounter trials of many kinds,","sources":{"KJV":{"text":"My brethren, count it all joy when ye fall into divers temptations;"},"BSB":{"text":"Consider it pure joy, my brothers, when you encounter trials of many kinds,"}},"definableWords":["joy"],"peopleInVerse":[]},"3":{"text":"Knowing this, that the trying of your faith worketh patience.","ref":"James 1:3","synthesized":"because you know that the testing of your faith develops perseverance.","sources":{"KJV":{"text":"Knowing this, that the trying of your faith worketh patience."},"BSB":{"text":"because you know that the testing of your faith develops perseverance."}},"definableWords":["faith"],"peopleInVerse":[]},"4":{"text":"But let patience have her perfect work, that ye may be perfect and entire, wanting nothing.","ref":"James 1:4","synthesized":"Allow perseverance to finish its work, so that you may be mature and complete, not lacking anything.","sources":{"KJV":{"text":"But let patience have her perfect work, that ye may be perfect and entire, wanting nothing."},"BSB":{"text":"Allow perseverance to finish its work, so that you may be mature and complete, not lacking anything."}},"definableWords":["work"],"peopleInVerse":[]},"5":{"text":"If any of you lack wisdom, let him ask of God, that giveth to all men liberally, and upbraideth not; and it shall be given him.","ref":"James 1:5","synthesized":"Now if any of you lacks wisdom, he should ask God, who gives generously to all without finding fault, and it will be given to him.","sources":{"KJV":{"text":"If any of you lack wisdom, let him ask of God, that giveth to all men liberally, and upbraideth not; and it shall be given him."},"BSB":{"text":"Now if any of you lacks wisdom, he should ask God, who gives generously to all without finding fault, and it will be given to him."}},"definableWords":["wisdom","God"],"peopleInVerse":[]},"6":{"text":"But let him ask in faith, nothing wavering. For he that wavereth is like a wave of the sea driven with the wind and tossed.","ref":"James 1:6","synthesized":"But he must ask in faith, without doubting, because he who doubts is like a wave of the sea, blown and tossed by the wind.","sources":{"KJV":{"text":"But let him ask in faith, nothing wavering. For he that wavereth is like a wave of the sea driven with the wind and tossed."},"BSB":{"text":"But he must ask in faith, without doubting, because he who doubts is like a wave of the sea, blown and tossed by the wind."}},"definableWords":["faith","sea"],"peopleInVerse":[]},"7":{"text":"For let not that man think that he shall receive any thing of the Lord.","ref":"James 1:7","synthesized":"That man should not expect to receive anything from the Lord.","sources":{"KJV":{"text":"For let not that man think that he shall receive any thing of the Lord."},"BSB":{"text":"That man should not expect to receive anything from the Lord."}},"definableWords":["man","Lord"],"peopleInVerse":[]},"8":{"text":"A double minded man is unstable in all his ways.","ref":"James 1:8","synthesized":"He is a double-minded man, unstable in all his ways.","sources":{"KJV":{"text":"A double minded man is unstable in all his ways."},"BSB":{"text":"He is a double-minded man, unstable in all his ways."}},"definableWords":["man"],"peopleInVerse":[]},"9":{"text":"Let the brother of low degree rejoice in that he is exalted:","ref":"James 1:9","synthesized":"The brother in humble circumstances should exult in his high position.","sources":{"KJV":{"text":"Let the brother of low degree rejoice in that he is exalted:"},"BSB":{"text":"The brother in humble circumstances should exult in his high position."}},"definableWords":["brother"],"peopleInVerse":[]},"10":{"text":"But the rich, in that he is made low: because as the flower of the grass he shall pass away.","ref":"James 1:10","synthesized":"But the one who is rich should exult in his low position, because he will pass away like a flower of the field.","sources":{"KJV":{"text":"But the rich, in that he is made low: because as the flower of the grass he shall pass away."},"BSB":{"text":"But the one who is rich should exult in his low position, because he will pass away like a flower of the field."}},"definableWords":["one","field"],"peopleInVerse":[]},"11":{"text":"For the sun is no sooner risen with a burning heat, but it withereth the grass, and the flower thereof falleth, and the grace of the fashion of it perisheth: so also shall the rich man fade away in his ways.","ref":"James 1:11","synthesized":"For the sun rises with scorching heat and withers the plant; its flower falls and its beauty is lost. So too, the rich man will fade away in the midst of his pursuits.","sources":{"KJV":{"text":"For the sun is no sooner risen with a burning heat, but it withereth the grass, and the flower thereof falleth, and the grace of the fashion of it perisheth: so also shall the rich man fade away in his ways."},"BSB":{"text":"For the sun rises with scorching heat and withers the plant; its flower falls and its beauty is lost. So too, the rich man will fade away in the midst of his pursuits."}},"definableWords":["man"],"peopleInVerse":[]},"12":{"text":"Blessed is the man that endureth temptation: for when he is tried, he shall receive the crown of life, which the Lord hath promised to them that love him.","ref":"James 1:12","synthesized":"Blessed is the man who perseveres under trial, because when he has stood the test, he will receive the crown of life that God has promised to those who love Him.","sources":{"KJV":{"text":"Blessed is the man that endureth temptation: for when he is tried, he shall receive the crown of life, which the Lord hath promised to them that love him."},"BSB":{"text":"Blessed is the man who perseveres under trial, because when he has stood the test, he will receive the crown of life that God has promised to those who love Him."}},"definableWords":["blessed","man","crown","life","God","love"],"peopleInVerse":[]},"13":{"text":"Let no man say when he is tempted, I am tempted of God: for God cannot be tempted with evil, neither tempteth he any man:","ref":"James 1:13","synthesized":"When tempted, no one should say, “God is tempting me.” For God cannot be tempted by evil, nor does He tempt anyone.","sources":{"KJV":{"text":"Let no man say when he is tempted, I am tempted of God: for God cannot be tempted with evil, neither tempteth he any man:"},"BSB":{"text":"When tempted, no one should say, “God is tempting me.” For God cannot be tempted by evil, nor does He tempt anyone."}},"definableWords":["one","God","evil"],"peopleInVerse":[]},"14":{"text":"But every man is tempted, when he is drawn away of his own lust, and enticed.","ref":"James 1:14","synthesized":"But each one is tempted when by his own evil desires he is lured away and enticed.","sources":{"KJV":{"text":"But every man is tempted, when he is drawn away of his own lust, and enticed."},"BSB":{"text":"But each one is tempted when by his own evil desires he is lured away and enticed."}},"definableWords":["one","evil"],"peopleInVerse":[]},"15":{"text":"Then when lust hath conceived, it bringeth forth sin: and sin, when it is finished, bringeth forth death.","ref":"James 1:15","synthesized":"Then after desire has conceived, it gives birth to sin; and sin, when it is full-grown, gives birth to death.","sources":{"KJV":{"text":"Then when lust hath conceived, it bringeth forth sin: and sin, when it is finished, bringeth forth death."},"BSB":{"text":"Then after desire has conceived, it gives birth to sin; and sin, when it is full-grown, gives birth to death."}},"definableWords":["sin","death"],"peopleInVerse":[]},"16":{"text":"Do not err, my beloved brethren.","ref":"James 1:16","synthesized":"Do not be deceived, my beloved brothers.","sources":{"KJV":{"text":"Do not err, my beloved brethren."},"BSB":{"text":"Do not be deceived, my beloved brothers."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Every good gift and every perfect gift is from above, and cometh down from the Father of lights, with whom is no variableness, neither shadow of turning.","ref":"James 1:17","synthesized":"Every good and perfect gift is from above, coming down from the Father of the heavenly lights, with whom there is no change or shifting shadow.","sources":{"KJV":{"text":"Every good gift and every perfect gift is from above, and cometh down from the Father of lights, with whom is no variableness, neither shadow of turning."},"BSB":{"text":"Every good and perfect gift is from above, coming down from the Father of the heavenly lights, with whom there is no change or shifting shadow."}},"definableWords":["good","Father","or"],"peopleInVerse":[]},"18":{"text":"Of his own will begat he us with the word of truth, that we should be a kind of firstfruits of his creatures.","ref":"James 1:18","synthesized":"He chose to give us birth through the word of truth, that we would be a kind of firstfruits of His creation.","sources":{"KJV":{"text":"Of his own will begat he us with the word of truth, that we should be a kind of firstfruits of his creatures."},"BSB":{"text":"He chose to give us birth through the word of truth, that we would be a kind of firstfruits of His creation."}},"definableWords":["word","truth"],"peopleInVerse":[]},"19":{"text":"Wherefore, my beloved brethren, let every man be swift to hear, slow to speak, slow to wrath:","ref":"James 1:19","synthesized":"My beloved brothers, understand this: Everyone should be quick to listen, slow to speak, and slow to anger,","sources":{"KJV":{"text":"Wherefore, my beloved brethren, let every man be swift to hear, slow to speak, slow to wrath:"},"BSB":{"text":"My beloved brothers, understand this: Everyone should be quick to listen, slow to speak, and slow to anger,"}},"definableWords":["anger"],"peopleInVerse":[]},"20":{"text":"For the wrath of man worketh not the righteousness of God.","ref":"James 1:20","synthesized":"for man’s anger does not bring about the righteousness that God desires.","sources":{"KJV":{"text":"For the wrath of man worketh not the righteousness of God."},"BSB":{"text":"for man’s anger does not bring about the righteousness that God desires."}},"definableWords":["man","anger","righteousness","God"],"peopleInVerse":[]},"21":{"text":"Wherefore lay apart all filthiness and superfluity of naughtiness, and receive with meekness the engrafted word, which is able to save your souls.","ref":"James 1:21","synthesized":"Therefore, get rid of all moral filth and every expression of evil, and humbly accept the word planted in you, which can save your souls.","sources":{"KJV":{"text":"Wherefore lay apart all filthiness and superfluity of naughtiness, and receive with meekness the engrafted word, which is able to save your souls."},"BSB":{"text":"Therefore, get rid of all moral filth and every expression of evil, and humbly accept the word planted in you, which can save your souls."}},"definableWords":["evil","word"],"peopleInVerse":[]},"22":{"text":"But be ye doers of the word, and not hearers only, deceiving your own selves.","ref":"James 1:22","synthesized":"Be doers of the word, and not hearers only. Otherwise, you are deceiving yourselves.","sources":{"KJV":{"text":"But be ye doers of the word, and not hearers only, deceiving your own selves."},"BSB":{"text":"Be doers of the word, and not hearers only. Otherwise, you are deceiving yourselves."}},"definableWords":["word"],"peopleInVerse":[]},"23":{"text":"For if any be a hearer of the word, and not a doer, he is like unto a man beholding his natural face in a glass:","ref":"James 1:23","synthesized":"For anyone who hears the word but does not carry it out is like a man who looks at his face in a mirror,","sources":{"KJV":{"text":"For if any be a hearer of the word, and not a doer, he is like unto a man beholding his natural face in a glass:"},"BSB":{"text":"For anyone who hears the word but does not carry it out is like a man who looks at his face in a mirror,"}},"definableWords":["word","man"],"peopleInVerse":[]},"24":{"text":"For he beholdeth himself, and goeth his way, and straightway forgetteth what manner of man he was.","ref":"James 1:24","synthesized":"and after observing himself goes away and immediately forgets what he looks like.","sources":{"KJV":{"text":"For he beholdeth himself, and goeth his way, and straightway forgetteth what manner of man he was."},"BSB":{"text":"and after observing himself goes away and immediately forgets what he looks like."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"But whoso looketh into the perfect law of liberty, and continueth therein, he being not a forgetful hearer, but a doer of the work, this man shall be blessed in his deed.","ref":"James 1:25","synthesized":"But the one who looks intently into the perfect law of freedom, and continues to do so—not being a forgetful hearer, but an effective doer—he will be blessed in what he does.","sources":{"KJV":{"text":"But whoso looketh into the perfect law of liberty, and continueth therein, he being not a forgetful hearer, but a doer of the work, this man shall be blessed in his deed."},"BSB":{"text":"But the one who looks intently into the perfect law of freedom, and continues to do so—not being a forgetful hearer, but an effective doer—he will be blessed in what he does."}},"definableWords":["one","law","blessed"],"peopleInVerse":[]},"26":{"text":"If any man among you seem to be religious, and bridleth not his tongue, but deceiveth his own heart, this man’s religion is vain.","ref":"James 1:26","synthesized":"If anyone considers himself religious and yet does not bridle his tongue, he deceives his heart and his religion is worthless.","sources":{"KJV":{"text":"If any man among you seem to be religious, and bridleth not his tongue, but deceiveth his own heart, this man’s religion is vain."},"BSB":{"text":"If anyone considers himself religious and yet does not bridle his tongue, he deceives his heart and his religion is worthless."}},"definableWords":["heart"],"peopleInVerse":[]},"27":{"text":"Pure religion and undefiled before God and the Father is this, To visit the fatherless and widows in their affliction, and to keep himself unspotted from the world.","ref":"James 1:27","synthesized":"Pure and undefiled religion before our God and Father is this: to care for orphans and widows in their distress, and to keep oneself from being polluted by the world.","sources":{"KJV":{"text":"Pure religion and undefiled before God and the Father is this, To visit the fatherless and widows in their affliction, and to keep himself unspotted from the world."},"BSB":{"text":"Pure and undefiled religion before our God and Father is this: to care for orphans and widows in their distress, and to keep oneself from being polluted by the world."}},"definableWords":["God","Father","keep"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"FAITH WITHOUT WORKS IS DEAD","verses":{"1":{"text":"My brethren, have not the faith of our Lord Jesus Christ, the Lord of glory, with respect of persons.","ref":"James 2:1","synthesized":"My brothers, as you hold out your faith in our glorious Lord Jesus Christ, do not show favoritism.","sources":{"KJV":{"text":"My brethren, have not the faith of our Lord Jesus Christ, the Lord of glory, with respect of persons."},"BSB":{"text":"My brothers, as you hold out your faith in our glorious Lord Jesus Christ, do not show favoritism."}},"definableWords":["faith","Lord","Christ"],"peopleInVerse":["Jesus"]},"2":{"text":"For if there come unto your assembly a man with a gold ring, in goodly apparel, and there come in also a poor man in vile raiment;","ref":"James 2:2","synthesized":"Suppose a man comes into your meeting wearing a gold ring and fine clothes, and a poor man in shabby clothes also comes in.","sources":{"KJV":{"text":"For if there come unto your assembly a man with a gold ring, in goodly apparel, and there come in also a poor man in vile raiment;"},"BSB":{"text":"Suppose a man comes into your meeting wearing a gold ring and fine clothes, and a poor man in shabby clothes also comes in."}},"definableWords":["man"],"peopleInVerse":[]},"3":{"text":"And ye have respect to him that weareth the gay clothing, and say unto him, Sit thou here in a good place; and say to the poor, Stand thou there, or sit here under my footstool:","ref":"James 2:3","synthesized":"If you lavish attention on the man in fine clothes and say, “Here is a seat of honor,” but say to the poor man, “You must stand” or “Sit at my feet,”","sources":{"KJV":{"text":"And ye have respect to him that weareth the gay clothing, and say unto him, Sit thou here in a good place; and say to the poor, Stand thou there, or sit here under my footstool:"},"BSB":{"text":"If you lavish attention on the man in fine clothes and say, “Here is a seat of honor,” but say to the poor man, “You must stand” or “Sit at my feet,”"}},"definableWords":["man","stand","or"],"peopleInVerse":[]},"4":{"text":"Are ye not then partial in yourselves, and are become judges of evil thoughts?","ref":"James 2:4","synthesized":"have you not discriminated among yourselves and become judges with evil thoughts?","sources":{"KJV":{"text":"Are ye not then partial in yourselves, and are become judges of evil thoughts?"},"BSB":{"text":"have you not discriminated among yourselves and become judges with evil thoughts?"}},"definableWords":["evil"],"peopleInVerse":[]},"5":{"text":"Hearken, my beloved brethren, Hath not God chosen the poor of this world rich in faith, and heirs of the kingdom which he hath promised to them that love him?","ref":"James 2:5","synthesized":"Listen, my beloved brothers: Has not God chosen the poor of this world to be rich in faith and to inherit the kingdom He promised those who love Him?","sources":{"KJV":{"text":"Hearken, my beloved brethren, Hath not God chosen the poor of this world rich in faith, and heirs of the kingdom which he hath promised to them that love him?"},"BSB":{"text":"Listen, my beloved brothers: Has not God chosen the poor of this world to be rich in faith and to inherit the kingdom He promised those who love Him?"}},"definableWords":["God","faith","inherit","kingdom","love"],"peopleInVerse":[]},"6":{"text":"But ye have despised the poor. Do not rich men oppress you, and draw you before the judgment seats?","ref":"James 2:6","synthesized":"But you have dishonored the poor. Is it not the rich who oppress you and drag you into court?","sources":{"KJV":{"text":"But ye have despised the poor. Do not rich men oppress you, and draw you before the judgment seats?"},"BSB":{"text":"But you have dishonored the poor. Is it not the rich who oppress you and drag you into court?"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Do not they blaspheme that worthy name by the which ye are called?","ref":"James 2:7","synthesized":"Are they not the ones who blaspheme the noble name by which you have been called?","sources":{"KJV":{"text":"Do not they blaspheme that worthy name by the which ye are called?"},"BSB":{"text":"Are they not the ones who blaspheme the noble name by which you have been called?"}},"definableWords":["name"],"peopleInVerse":[]},"8":{"text":"If ye fulfil the royal law according to the scripture, Thou shalt love thy neighbour as thyself, ye do well:","ref":"James 2:8","synthesized":"If you really fulfill the royal law stated in Scripture, “Love your neighbor as yourself,” you are doing well.","sources":{"KJV":{"text":"If ye fulfil the royal law according to the scripture, Thou shalt love thy neighbour as thyself, ye do well:"},"BSB":{"text":"If you really fulfill the royal law stated in Scripture, “Love your neighbor as yourself,” you are doing well."}},"definableWords":["law","love"],"peopleInVerse":[]},"9":{"text":"But if ye have respect to persons, ye commit sin, and are convinced of the law as transgressors.","ref":"James 2:9","synthesized":"But if you show favoritism, you sin and are convicted by the law as transgressors.","sources":{"KJV":{"text":"But if ye have respect to persons, ye commit sin, and are convinced of the law as transgressors."},"BSB":{"text":"But if you show favoritism, you sin and are convicted by the law as transgressors."}},"definableWords":["sin","law"],"peopleInVerse":[]},"10":{"text":"For whosoever shall keep the whole law, and yet offend in one point, he is guilty of all.","ref":"James 2:10","synthesized":"Whoever keeps the whole law but stumbles at just one point is guilty of breaking all of it.","sources":{"KJV":{"text":"For whosoever shall keep the whole law, and yet offend in one point, he is guilty of all."},"BSB":{"text":"Whoever keeps the whole law but stumbles at just one point is guilty of breaking all of it."}},"definableWords":["law","one"],"peopleInVerse":[]},"11":{"text":"For he that said, Do not commit adultery, said also, Do not kill. Now if thou commit no adultery, yet if thou kill, thou art become a transgressor of the law.","ref":"James 2:11","synthesized":"For He who said, “Do not commit adultery,” also said, “Do not murder.” If you do not commit adultery, but do commit murder, you have become a lawbreaker.","sources":{"KJV":{"text":"For he that said, Do not commit adultery, said also, Do not kill. Now if thou commit no adultery, yet if thou kill, thou art become a transgressor of the law."},"BSB":{"text":"For He who said, “Do not commit adultery,” also said, “Do not murder.” If you do not commit adultery, but do commit murder, you have become a lawbreaker."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"So speak ye, and so do, as they that shall be judged by the law of liberty.","ref":"James 2:12","synthesized":"Speak and act as those who are going to be judged by the law that gives freedom.","sources":{"KJV":{"text":"So speak ye, and so do, as they that shall be judged by the law of liberty."},"BSB":{"text":"Speak and act as those who are going to be judged by the law that gives freedom."}},"definableWords":["law"],"peopleInVerse":[]},"13":{"text":"For he shall have judgment without mercy, that hath shewed no mercy; and mercy rejoiceth against judgment.","ref":"James 2:13","synthesized":"For judgment without mercy will be shown to anyone who has not been merciful. Mercy triumphs over judgment.","sources":{"KJV":{"text":"For he shall have judgment without mercy, that hath shewed no mercy; and mercy rejoiceth against judgment."},"BSB":{"text":"For judgment without mercy will be shown to anyone who has not been merciful. Mercy triumphs over judgment."}},"definableWords":["judgment","mercy"],"peopleInVerse":[]},"14":{"text":"What doth it profit, my brethren, though a man say he hath faith, and have not works? can faith save him?","ref":"James 2:14","synthesized":"What good is it, my brothers, if someone claims to have faith, but has no deeds? Can such faith save him?","sources":{"KJV":{"text":"What doth it profit, my brethren, though a man say he hath faith, and have not works? can faith save him?"},"BSB":{"text":"What good is it, my brothers, if someone claims to have faith, but has no deeds? Can such faith save him?"}},"definableWords":["good","faith"],"peopleInVerse":[]},"15":{"text":"If a brother or sister be naked, and destitute of daily food,","ref":"James 2:15","synthesized":"Suppose a brother or sister is without clothes and daily food.","sources":{"KJV":{"text":"If a brother or sister be naked, and destitute of daily food,"},"BSB":{"text":"Suppose a brother or sister is without clothes and daily food."}},"definableWords":["brother","or","sister"],"peopleInVerse":[]},"16":{"text":"And one of you say unto them, Depart in peace, be ye warmed and filled; notwithstanding ye give them not those things which are needful to the body; what doth it profit?","ref":"James 2:16","synthesized":"If one of you tells him, “Go in peace; stay warm and well fed,” but does not provide for his physical needs, what good is that?","sources":{"KJV":{"text":"And one of you say unto them, Depart in peace, be ye warmed and filled; notwithstanding ye give them not those things which are needful to the body; what doth it profit?"},"BSB":{"text":"If one of you tells him, “Go in peace; stay warm and well fed,” but does not provide for his physical needs, what good is that?"}},"definableWords":["one","peace","good"],"peopleInVerse":[]},"17":{"text":"Even so faith, if it hath not works, is dead, being alone.","ref":"James 2:17","synthesized":"So too, faith by itself, if it does not result in action, is dead.","sources":{"KJV":{"text":"Even so faith, if it hath not works, is dead, being alone."},"BSB":{"text":"So too, faith by itself, if it does not result in action, is dead."}},"definableWords":["faith"],"peopleInVerse":[]},"18":{"text":"Yea, a man may say, Thou hast faith, and I have works: shew me thy faith without thy works, and I will shew thee my faith by my works.","ref":"James 2:18","synthesized":"But someone will say, “You have faith and I have deeds.” Show me your faith without deeds, and I will show you my faith by my deeds.","sources":{"KJV":{"text":"Yea, a man may say, Thou hast faith, and I have works: shew me thy faith without thy works, and I will shew thee my faith by my works."},"BSB":{"text":"But someone will say, “You have faith and I have deeds.” Show me your faith without deeds, and I will show you my faith by my deeds."}},"definableWords":["faith"],"peopleInVerse":[]},"19":{"text":"Thou believest that there is one God; thou doest well: the devils also believe, and tremble.","ref":"James 2:19","synthesized":"You believe that God is one. Good for you! Even the demons believe that—and shudder.","sources":{"KJV":{"text":"Thou believest that there is one God; thou doest well: the devils also believe, and tremble."},"BSB":{"text":"You believe that God is one. Good for you! Even the demons believe that—and shudder."}},"definableWords":["God","one","good"],"peopleInVerse":[]},"20":{"text":"But wilt thou know, O vain man, that faith without works is dead?","ref":"James 2:20","synthesized":"O foolish man, do you want evidence that faith without deeds is worthless?","sources":{"KJV":{"text":"But wilt thou know, O vain man, that faith without works is dead?"},"BSB":{"text":"O foolish man, do you want evidence that faith without deeds is worthless?"}},"definableWords":["man","faith"],"peopleInVerse":[]},"21":{"text":"Was not Abraham our father justified by works, when he had offered Isaac his son upon the altar?","ref":"James 2:21","synthesized":"Was not our father Abraham justified by what he did when he offered his son Isaac on the altar?","sources":{"KJV":{"text":"Was not Abraham our father justified by works, when he had offered Isaac his son upon the altar?"},"BSB":{"text":"Was not our father Abraham justified by what he did when he offered his son Isaac on the altar?"}},"definableWords":["father","Abraham","son","Isaac","altar"],"peopleInVerse":["Abraham","Isaac"]},"22":{"text":"Seest thou how faith wrought with his works, and by works was faith made perfect?","ref":"James 2:22","synthesized":"You see that his faith was working with his actions, and his faith was perfected by what he did.","sources":{"KJV":{"text":"Seest thou how faith wrought with his works, and by works was faith made perfect?"},"BSB":{"text":"You see that his faith was working with his actions, and his faith was perfected by what he did."}},"definableWords":["see","faith"],"peopleInVerse":[]},"23":{"text":"And the scripture was fulfilled which saith, Abraham believed God, and it was imputed unto him for righteousness: and he was called the Friend of God.","ref":"James 2:23","synthesized":"And the Scripture was fulfilled that says, “Abraham believed God, and it was credited to him as righteousness,” and he was called a friend of God.","sources":{"KJV":{"text":"And the scripture was fulfilled which saith, Abraham believed God, and it was imputed unto him for righteousness: and he was called the Friend of God."},"BSB":{"text":"And the Scripture was fulfilled that says, “Abraham believed God, and it was credited to him as righteousness,” and he was called a friend of God."}},"definableWords":["Abraham","believed","God","righteousness"],"peopleInVerse":["Abraham"]},"24":{"text":"Ye see then how that by works a man is justified, and not by faith only.","ref":"James 2:24","synthesized":"As you can see, a man is justified by his deeds and not by faith alone.","sources":{"KJV":{"text":"Ye see then how that by works a man is justified, and not by faith only."},"BSB":{"text":"As you can see, a man is justified by his deeds and not by faith alone."}},"definableWords":["see","man","faith"],"peopleInVerse":[]},"25":{"text":"Likewise also was not Rahab the harlot justified by works, when she had received the messengers, and had sent them out another way?","ref":"James 2:25","synthesized":"In the same way, was not even Rahab the prostitute justified by her actions when she welcomed the spies and sent them off on another route?","sources":{"KJV":{"text":"Likewise also was not Rahab the harlot justified by works, when she had received the messengers, and had sent them out another way?"},"BSB":{"text":"In the same way, was not even Rahab the prostitute justified by her actions when she welcomed the spies and sent them off on another route?"}},"definableWords":["way"],"peopleInVerse":["Rahab"]},"26":{"text":"For as the body without the spirit is dead, so faith without works is dead also.","ref":"James 2:26","synthesized":"As the body without the spirit is dead, so faith without deeds is dead.","sources":{"KJV":{"text":"For as the body without the spirit is dead, so faith without works is dead also."},"BSB":{"text":"As the body without the spirit is dead, so faith without deeds is dead."}},"definableWords":["spirit","faith"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"THE TONGUE","verses":{"1":{"text":"My brethren, be not many masters, knowing that we shall receive the greater condemnation.","ref":"James 3:1","synthesized":"Not many of you should become teachers, my brothers, because you know that we who teach will be judged more strictly.","sources":{"KJV":{"text":"My brethren, be not many masters, knowing that we shall receive the greater condemnation."},"BSB":{"text":"Not many of you should become teachers, my brothers, because you know that we who teach will be judged more strictly."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"For in many things we offend all. If any man offend not in word, the same is a perfect man, and able also to bridle the whole body.","ref":"James 3:2","synthesized":"We all stumble in many ways. If anyone is never at fault in what he says, he is a perfect man, able to control his whole body.","sources":{"KJV":{"text":"For in many things we offend all. If any man offend not in word, the same is a perfect man, and able also to bridle the whole body."},"BSB":{"text":"We all stumble in many ways. If anyone is never at fault in what he says, he is a perfect man, able to control his whole body."}},"definableWords":["man"],"peopleInVerse":[]},"3":{"text":"Behold, we put bits in the horses’ mouths, that they may obey us; and we turn about their whole body.","ref":"James 3:3","synthesized":"When we put bits into the mouths of horses to make them obey us, we can guide the whole animal.","sources":{"KJV":{"text":"Behold, we put bits in the horses’ mouths, that they may obey us; and we turn about their whole body."},"BSB":{"text":"When we put bits into the mouths of horses to make them obey us, we can guide the whole animal."}},"definableWords":["make"],"peopleInVerse":[]},"4":{"text":"Behold also the ships, which though they be so great, and are driven of fierce winds, yet are they turned about with a very small helm, whithersoever the governor listeth.","ref":"James 3:4","synthesized":"Consider ships as well. Although they are so large and are driven by strong winds, they are steered by a very small rudder wherever the pilot is inclined.","sources":{"KJV":{"text":"Behold also the ships, which though they be so great, and are driven of fierce winds, yet are they turned about with a very small helm, whithersoever the governor listeth."},"BSB":{"text":"Consider ships as well. Although they are so large and are driven by strong winds, they are steered by a very small rudder wherever the pilot is inclined."}},"definableWords":["strong"],"peopleInVerse":[]},"5":{"text":"Even so the tongue is a little member, and boasteth great things. Behold, how great a matter a little fire kindleth!","ref":"James 3:5","synthesized":"In the same way, the tongue is a small part of the body, but it boasts of great things. Consider how small a spark sets a great forest ablaze.","sources":{"KJV":{"text":"Even so the tongue is a little member, and boasteth great things. Behold, how great a matter a little fire kindleth!"},"BSB":{"text":"In the same way, the tongue is a small part of the body, but it boasts of great things. Consider how small a spark sets a great forest ablaze."}},"definableWords":["way","great"],"peopleInVerse":[]},"6":{"text":"And the tongue is a fire, a world of iniquity: so is the tongue among our members, that it defileth the whole body, and setteth on fire the course of nature; and it is set on fire of hell.","ref":"James 3:6","synthesized":"The tongue also is a fire, a world of wickedness among the parts of the body. It pollutes the whole person, sets the course of his life on fire, and is itself set on fire by hell.","sources":{"KJV":{"text":"And the tongue is a fire, a world of iniquity: so is the tongue among our members, that it defileth the whole body, and setteth on fire the course of nature; and it is set on fire of hell."},"BSB":{"text":"The tongue also is a fire, a world of wickedness among the parts of the body. It pollutes the whole person, sets the course of his life on fire, and is itself set on fire by hell."}},"definableWords":["life","hell"],"peopleInVerse":[]},"7":{"text":"For every kind of beasts, and of birds, and of serpents, and of things in the sea, is tamed, and hath been tamed of mankind:","ref":"James 3:7","synthesized":"All kinds of animals, birds, reptiles, and creatures of the sea are being tamed and have been tamed by man,","sources":{"KJV":{"text":"For every kind of beasts, and of birds, and of serpents, and of things in the sea, is tamed, and hath been tamed of mankind:"},"BSB":{"text":"All kinds of animals, birds, reptiles, and creatures of the sea are being tamed and have been tamed by man,"}},"definableWords":["birds","sea","man"],"peopleInVerse":[]},"8":{"text":"But the tongue can no man tame; it is an unruly evil, full of deadly poison.","ref":"James 3:8","synthesized":"but no man can tame the tongue. It is a restless evil, full of deadly poison.","sources":{"KJV":{"text":"But the tongue can no man tame; it is an unruly evil, full of deadly poison."},"BSB":{"text":"but no man can tame the tongue. It is a restless evil, full of deadly poison."}},"definableWords":["man","evil"],"peopleInVerse":[]},"9":{"text":"Therewith bless we God, even the Father; and therewith curse we men, which are made after the similitude of God.","ref":"James 3:9","synthesized":"With the tongue we bless our Lord and Father, and with it we curse men, who have been made in God’s likeness.","sources":{"KJV":{"text":"Therewith bless we God, even the Father; and therewith curse we men, which are made after the similitude of God."},"BSB":{"text":"With the tongue we bless our Lord and Father, and with it we curse men, who have been made in God’s likeness."}},"definableWords":["bless","Lord","Father","curse","men","made","God","likeness"],"peopleInVerse":[]},"10":{"text":"Out of the same mouth proceedeth blessing and cursing. My brethren, these things ought not so to be.","ref":"James 3:10","synthesized":"Out of the same mouth come blessing and cursing. My brothers, this should not be!","sources":{"KJV":{"text":"Out of the same mouth proceedeth blessing and cursing. My brethren, these things ought not so to be."},"BSB":{"text":"Out of the same mouth come blessing and cursing. My brothers, this should not be!"}},"definableWords":["blessing"],"peopleInVerse":[]},"11":{"text":"Doth a fountain send forth at the same place sweet water and bitter?","ref":"James 3:11","synthesized":"Can both fresh water and salt water flow from the same spring?","sources":{"KJV":{"text":"Doth a fountain send forth at the same place sweet water and bitter?"},"BSB":{"text":"Can both fresh water and salt water flow from the same spring?"}},"definableWords":["water"],"peopleInVerse":[]},"12":{"text":"Can the fig tree, my brethren, bear olive berries? either a vine, figs? so can no fountain both yield salt water and fresh.","ref":"James 3:12","synthesized":"My brothers, can a fig tree grow olives, or a grapevine bear figs? Neither can a salt spring produce fresh water.","sources":{"KJV":{"text":"Can the fig tree, my brethren, bear olive berries? either a vine, figs? so can no fountain both yield salt water and fresh."},"BSB":{"text":"My brothers, can a fig tree grow olives, or a grapevine bear figs? Neither can a salt spring produce fresh water."}},"definableWords":["tree","or","water"],"peopleInVerse":[]},"13":{"text":"Who is a wise man and endued with knowledge among you? let him shew out of a good conversation his works with meekness of wisdom.","ref":"James 3:13","synthesized":"Who is wise and understanding among you? Let him show it by his good conduct, by deeds done in the humility that comes from wisdom.","sources":{"KJV":{"text":"Who is a wise man and endued with knowledge among you? let him shew out of a good conversation his works with meekness of wisdom."},"BSB":{"text":"Who is wise and understanding among you? Let him show it by his good conduct, by deeds done in the humility that comes from wisdom."}},"definableWords":["good","wisdom"],"peopleInVerse":[]},"14":{"text":"But if ye have bitter envying and strife in your hearts, glory not, and lie not against the truth.","ref":"James 3:14","synthesized":"But if you harbor bitter jealousy and selfish ambition in your hearts, do not boast in it or deny the truth.","sources":{"KJV":{"text":"But if ye have bitter envying and strife in your hearts, glory not, and lie not against the truth."},"BSB":{"text":"But if you harbor bitter jealousy and selfish ambition in your hearts, do not boast in it or deny the truth."}},"definableWords":["or","truth"],"peopleInVerse":[]},"15":{"text":"This wisdom descendeth not from above, but is earthly, sensual, devilish.","ref":"James 3:15","synthesized":"Such wisdom does not come from above, but is earthly, unspiritual, demonic.","sources":{"KJV":{"text":"This wisdom descendeth not from above, but is earthly, sensual, devilish."},"BSB":{"text":"Such wisdom does not come from above, but is earthly, unspiritual, demonic."}},"definableWords":["wisdom"],"peopleInVerse":[]},"16":{"text":"For where envying and strife is, there is confusion and every evil work.","ref":"James 3:16","synthesized":"For where jealousy and selfish ambition exist, there will be disorder and every evil practice.","sources":{"KJV":{"text":"For where envying and strife is, there is confusion and every evil work."},"BSB":{"text":"For where jealousy and selfish ambition exist, there will be disorder and every evil practice."}},"definableWords":["evil"],"peopleInVerse":[]},"17":{"text":"But the wisdom that is from above is first pure, then peaceable, gentle, and easy to be intreated, full of mercy and good fruits, without partiality, and without hypocrisy.","ref":"James 3:17","synthesized":"But the wisdom from above is first of all pure, then peace-loving, gentle, accommodating, full of mercy and good fruit, impartial, and sincere.","sources":{"KJV":{"text":"But the wisdom that is from above is first pure, then peaceable, gentle, and easy to be intreated, full of mercy and good fruits, without partiality, and without hypocrisy."},"BSB":{"text":"But the wisdom from above is first of all pure, then peace-loving, gentle, accommodating, full of mercy and good fruit, impartial, and sincere."}},"definableWords":["wisdom","peace","mercy","good"],"peopleInVerse":[]},"18":{"text":"And the fruit of righteousness is sown in peace of them that make peace.","ref":"James 3:18","synthesized":"Peacemakers who sow in peace reap the fruit of righteousness.","sources":{"KJV":{"text":"And the fruit of righteousness is sown in peace of them that make peace."},"BSB":{"text":"Peacemakers who sow in peace reap the fruit of righteousness."}},"definableWords":["peace","righteousness"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"DRAW NIGH TO GOD","verses":{"1":{"text":"From whence come wars and fightings among you? come they not hence, even of your lusts that war in your members?","ref":"James 4:1","synthesized":"What causes conflicts and quarrels among you? Don’t they come from the passions at war within you?","sources":{"KJV":{"text":"From whence come wars and fightings among you? come they not hence, even of your lusts that war in your members?"},"BSB":{"text":"What causes conflicts and quarrels among you? Don’t they come from the passions at war within you?"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Ye lust, and have not: ye kill, and desire to have, and cannot obtain: ye fight and war, yet ye have not, because ye ask not.","ref":"James 4:2","synthesized":"You crave what you do not have; you kill and covet, but are unable to obtain it. You quarrel and fight. You do not have, because you do not ask.","sources":{"KJV":{"text":"Ye lust, and have not: ye kill, and desire to have, and cannot obtain: ye fight and war, yet ye have not, because ye ask not."},"BSB":{"text":"You crave what you do not have; you kill and covet, but are unable to obtain it. You quarrel and fight. You do not have, because you do not ask."}},"definableWords":["fight"],"peopleInVerse":[]},"3":{"text":"Ye ask, and receive not, because ye ask amiss, that ye may consume it upon your lusts.","ref":"James 4:3","synthesized":"And when you do ask, you do not receive, because you ask with wrong motives, that you may squander it on your pleasures.","sources":{"KJV":{"text":"Ye ask, and receive not, because ye ask amiss, that ye may consume it upon your lusts."},"BSB":{"text":"And when you do ask, you do not receive, because you ask with wrong motives, that you may squander it on your pleasures."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Ye adulterers and adulteresses, know ye not that the friendship of the world is enmity with God? whosoever therefore will be a friend of the world is the enemy of God.","ref":"James 4:4","synthesized":"You adulteresses! Do you not know that friendship with the world is hostility toward God? Therefore, whoever chooses to be a friend of the world renders himself an enemy of God.","sources":{"KJV":{"text":"Ye adulterers and adulteresses, know ye not that the friendship of the world is enmity with God? whosoever therefore will be a friend of the world is the enemy of God."},"BSB":{"text":"You adulteresses! Do you not know that friendship with the world is hostility toward God? Therefore, whoever chooses to be a friend of the world renders himself an enemy of God."}},"definableWords":["God"],"peopleInVerse":[]},"5":{"text":"Do ye think that the scripture saith in vain, The spirit that dwelleth in us lusteth to envy?","ref":"James 4:5","synthesized":"Or do you think the Scripture says without reason that the Spirit He caused to dwell in us yearns with envy?","sources":{"KJV":{"text":"Do ye think that the scripture saith in vain, The spirit that dwelleth in us lusteth to envy?"},"BSB":{"text":"Or do you think the Scripture says without reason that the Spirit He caused to dwell in us yearns with envy?"}},"definableWords":["or","Spirit"],"peopleInVerse":[]},"6":{"text":"But he giveth more grace. Wherefore he saith, God resisteth the proud, but giveth grace unto the humble.","ref":"James 4:6","synthesized":"But He gives us more grace. This is why it says:  “God opposes the proud, but gives grace to the humble.”","sources":{"KJV":{"text":"But he giveth more grace. Wherefore he saith, God resisteth the proud, but giveth grace unto the humble."},"BSB":{"text":"But He gives us more grace. This is why it says:  “God opposes the proud, but gives grace to the humble.”"}},"definableWords":["grace","God"],"peopleInVerse":[]},"7":{"text":"Submit yourselves therefore to God. Resist the devil, and he will flee from you.","ref":"James 4:7","synthesized":"Submit yourselves, then, to God. Resist the devil, and he will flee from you.","sources":{"KJV":{"text":"Submit yourselves therefore to God. Resist the devil, and he will flee from you."},"BSB":{"text":"Submit yourselves, then, to God. Resist the devil, and he will flee from you."}},"definableWords":["God","devil"],"peopleInVerse":[]},"8":{"text":"Draw nigh to God, and he will draw nigh to you. Cleanse your hands, ye sinners; and purify your hearts, ye double minded.","ref":"James 4:8","synthesized":"Draw near to God, and He will draw near to you. Cleanse your hands, you sinners, and purify your hearts, you double-minded.","sources":{"KJV":{"text":"Draw nigh to God, and he will draw nigh to you. Cleanse your hands, ye sinners; and purify your hearts, ye double minded."},"BSB":{"text":"Draw near to God, and He will draw near to you. Cleanse your hands, you sinners, and purify your hearts, you double-minded."}},"definableWords":["God","cleanse"],"peopleInVerse":[]},"9":{"text":"Be afflicted, and mourn, and weep: let your laughter be turned to mourning, and your joy to heaviness.","ref":"James 4:9","synthesized":"Grieve, mourn, and weep. Turn your laughter to mourning, and your joy to gloom.","sources":{"KJV":{"text":"Be afflicted, and mourn, and weep: let your laughter be turned to mourning, and your joy to heaviness."},"BSB":{"text":"Grieve, mourn, and weep. Turn your laughter to mourning, and your joy to gloom."}},"definableWords":["joy"],"peopleInVerse":[]},"10":{"text":"Humble yourselves in the sight of the Lord, and he shall lift you up.","ref":"James 4:10","synthesized":"Humble yourselves before the Lord, and He will exalt you.","sources":{"KJV":{"text":"Humble yourselves in the sight of the Lord, and he shall lift you up."},"BSB":{"text":"Humble yourselves before the Lord, and He will exalt you."}},"definableWords":["Lord"],"peopleInVerse":[]},"11":{"text":"Speak not evil one of another, brethren. He that speaketh evil of his brother, and judgeth his brother, speaketh evil of the law, and judgeth the law: but if thou judge the law, thou art not a doer of the law, but a judge.","ref":"James 4:11","synthesized":"Brothers, do not slander one another. Anyone who speaks against his brother or judges him speaks against the law and judges it. And if you judge the law, you are not a practitioner of the law, but a judge of it.","sources":{"KJV":{"text":"Speak not evil one of another, brethren. He that speaketh evil of his brother, and judgeth his brother, speaketh evil of the law, and judgeth the law: but if thou judge the law, thou art not a doer of the law, but a judge."},"BSB":{"text":"Brothers, do not slander one another. Anyone who speaks against his brother or judges him speaks against the law and judges it. And if you judge the law, you are not a practitioner of the law, but a judge of it."}},"definableWords":["one","brother","or","law"],"peopleInVerse":[]},"12":{"text":"There is one lawgiver, who is able to save and to destroy: who art thou that judgest another?","ref":"James 4:12","synthesized":"There is only one Lawgiver and Judge, the One who is able to save and destroy. But who are you to judge your neighbor?","sources":{"KJV":{"text":"There is one lawgiver, who is able to save and to destroy: who art thou that judgest another?"},"BSB":{"text":"There is only one Lawgiver and Judge, the One who is able to save and destroy. But who are you to judge your neighbor?"}},"definableWords":["one"],"peopleInVerse":[]},"13":{"text":"Go to now, ye that say, To day or to morrow we will go into such a city, and continue there a year, and buy and sell, and get gain:","ref":"James 4:13","synthesized":"Come now, you who say, “Today or tomorrow we will go to this or that city, spend a year there, carry on business, and make a profit.”","sources":{"KJV":{"text":"Go to now, ye that say, To day or to morrow we will go into such a city, and continue there a year, and buy and sell, and get gain:"},"BSB":{"text":"Come now, you who say, “Today or tomorrow we will go to this or that city, spend a year there, carry on business, and make a profit.”"}},"definableWords":["or","year","make"],"peopleInVerse":[]},"14":{"text":"Whereas ye know not what shall be on the morrow. For what is your life? It is even a vapour, that appeareth for a little time, and then vanisheth away.","ref":"James 4:14","synthesized":"You do not even know what will happen tomorrow! What is your life? You are a mist that appears for a little while and then vanishes.","sources":{"KJV":{"text":"Whereas ye know not what shall be on the morrow. For what is your life? It is even a vapour, that appeareth for a little time, and then vanisheth away."},"BSB":{"text":"You do not even know what will happen tomorrow! What is your life? You are a mist that appears for a little while and then vanishes."}},"definableWords":["life"],"peopleInVerse":[]},"15":{"text":"For that ye ought to say, If the Lord will, we shall live, and do this, or that.","ref":"James 4:15","synthesized":"Instead, you ought to say, “If the Lord is willing, we will live and do this or that.”","sources":{"KJV":{"text":"For that ye ought to say, If the Lord will, we shall live, and do this, or that."},"BSB":{"text":"Instead, you ought to say, “If the Lord is willing, we will live and do this or that.”"}},"definableWords":["Lord","live","or"],"peopleInVerse":[]},"16":{"text":"But now ye rejoice in your boastings: all such rejoicing is evil.","ref":"James 4:16","synthesized":"As it is, you boast in your proud intentions. All such boasting is evil.","sources":{"KJV":{"text":"But now ye rejoice in your boastings: all such rejoicing is evil."},"BSB":{"text":"As it is, you boast in your proud intentions. All such boasting is evil."}},"definableWords":["evil"],"peopleInVerse":[]},"17":{"text":"Therefore to him that knoweth to do good, and doeth it not, to him it is sin.","ref":"James 4:17","synthesized":"Anyone, then, who knows the right thing to do, yet fails to do it, is guilty of sin.","sources":{"KJV":{"text":"Therefore to him that knoweth to do good, and doeth it not, to him it is sin."},"BSB":{"text":"Anyone, then, who knows the right thing to do, yet fails to do it, is guilty of sin."}},"definableWords":["sin"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"THE PRAYER OF FAITH","verses":{"1":{"text":"Go to now, ye rich men, weep and howl for your miseries that shall come upon you.","ref":"James 5:1","synthesized":"Come now, you who are rich, weep and wail over the misery to come upon you.","sources":{"KJV":{"text":"Go to now, ye rich men, weep and howl for your miseries that shall come upon you."},"BSB":{"text":"Come now, you who are rich, weep and wail over the misery to come upon you."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Your riches are corrupted, and your garments are motheaten.","ref":"James 5:2","synthesized":"Your riches have rotted and moths have eaten your clothes.","sources":{"KJV":{"text":"Your riches are corrupted, and your garments are motheaten."},"BSB":{"text":"Your riches have rotted and moths have eaten your clothes."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Your gold and silver is cankered; and the rust of them shall be a witness against you, and shall eat your flesh as it were fire. Ye have heaped treasure together for the last days.","ref":"James 5:3","synthesized":"Your gold and silver are corroded. Their corrosion will testify against you and consume your flesh like fire.  You have hoarded treasure in the last days.","sources":{"KJV":{"text":"Your gold and silver is cankered; and the rust of them shall be a witness against you, and shall eat your flesh as it were fire. Ye have heaped treasure together for the last days."},"BSB":{"text":"Your gold and silver are corroded. Their corrosion will testify against you and consume your flesh like fire.  You have hoarded treasure in the last days."}},"definableWords":["flesh","days"],"peopleInVerse":[]},"4":{"text":"Behold, the hire of the labourers who have reaped down your fields, which is of you kept back by fraud, crieth: and the cries of them which have reaped are entered into the ears of the Lord of sabaoth.","ref":"James 5:4","synthesized":"Look, the wages you withheld from the workmen who mowed your fields are crying out against you. The cries of the harvesters have reached the ears of the Lord of Hosts.","sources":{"KJV":{"text":"Behold, the hire of the labourers who have reaped down your fields, which is of you kept back by fraud, crieth: and the cries of them which have reaped are entered into the ears of the Lord of sabaoth."},"BSB":{"text":"Look, the wages you withheld from the workmen who mowed your fields are crying out against you. The cries of the harvesters have reached the ears of the Lord of Hosts."}},"definableWords":["Lord"],"peopleInVerse":[]},"5":{"text":"Ye have lived in pleasure on the earth, and been wanton; ye have nourished your hearts, as in a day of slaughter.","ref":"James 5:5","synthesized":"You have lived on earth in luxury and self-indulgence. You have fattened your hearts in the day of slaughter.","sources":{"KJV":{"text":"Ye have lived in pleasure on the earth, and been wanton; ye have nourished your hearts, as in a day of slaughter."},"BSB":{"text":"You have lived on earth in luxury and self-indulgence. You have fattened your hearts in the day of slaughter."}},"definableWords":["earth","day"],"peopleInVerse":[]},"6":{"text":"Ye have condemned and killed the just; and he doth not resist you.","ref":"James 5:6","synthesized":"You have condemned and murdered the righteous, who did not resist you.","sources":{"KJV":{"text":"Ye have condemned and killed the just; and he doth not resist you."},"BSB":{"text":"You have condemned and murdered the righteous, who did not resist you."}},"definableWords":["righteous"],"peopleInVerse":[]},"7":{"text":"Be patient therefore, brethren, unto the coming of the Lord. Behold, the husbandman waiteth for the precious fruit of the earth, and hath long patience for it, until he receive the early and latter rain.","ref":"James 5:7","synthesized":"Be patient, then, brothers, until the Lord’s coming. See how the farmer awaits the precious fruit of the soil—how patient he is for the fall and spring rains.","sources":{"KJV":{"text":"Be patient therefore, brethren, unto the coming of the Lord. Behold, the husbandman waiteth for the precious fruit of the earth, and hath long patience for it, until he receive the early and latter rain."},"BSB":{"text":"Be patient, then, brothers, until the Lord’s coming. See how the farmer awaits the precious fruit of the soil—how patient he is for the fall and spring rains."}},"definableWords":["Lord","see"],"peopleInVerse":[]},"8":{"text":"Be ye also patient; stablish your hearts: for the coming of the Lord draweth nigh.","ref":"James 5:8","synthesized":"You, too, be patient and strengthen your hearts, because the Lord’s coming is near.","sources":{"KJV":{"text":"Be ye also patient; stablish your hearts: for the coming of the Lord draweth nigh."},"BSB":{"text":"You, too, be patient and strengthen your hearts, because the Lord’s coming is near."}},"definableWords":["Lord"],"peopleInVerse":[]},"9":{"text":"Grudge not one against another, brethren, lest ye be condemned: behold, the judge standeth before the door.","ref":"James 5:9","synthesized":"Do not complain about one another, brothers, so that you will not be judged. Look, the Judge is standing at the door!","sources":{"KJV":{"text":"Grudge not one against another, brethren, lest ye be condemned: behold, the judge standeth before the door."},"BSB":{"text":"Do not complain about one another, brothers, so that you will not be judged. Look, the Judge is standing at the door!"}},"definableWords":["one"],"peopleInVerse":[]},"10":{"text":"Take, my brethren, the prophets, who have spoken in the name of the Lord, for an example of suffering affliction, and of patience.","ref":"James 5:10","synthesized":"Brothers, as an example of patience in affliction, take the prophets who spoke in the name of the Lord.","sources":{"KJV":{"text":"Take, my brethren, the prophets, who have spoken in the name of the Lord, for an example of suffering affliction, and of patience."},"BSB":{"text":"Brothers, as an example of patience in affliction, take the prophets who spoke in the name of the Lord."}},"definableWords":["patience","name","Lord"],"peopleInVerse":[]},"11":{"text":"Behold, we count them happy which endure. Ye have heard of the patience of Job, and have seen the end of the Lord; that the Lord is very pitiful, and of tender mercy.","ref":"James 5:11","synthesized":"See how blessed we consider those who have persevered. You have heard of Job’s perseverance and have seen the outcome from the Lord. The Lord is full of compassion and mercy.","sources":{"KJV":{"text":"Behold, we count them happy which endure. Ye have heard of the patience of Job, and have seen the end of the Lord; that the Lord is very pitiful, and of tender mercy."},"BSB":{"text":"See how blessed we consider those who have persevered. You have heard of Job’s perseverance and have seen the outcome from the Lord. The Lord is full of compassion and mercy."}},"definableWords":["see","blessed","Lord","mercy"],"peopleInVerse":[]},"12":{"text":"But above all things, my brethren, swear not, neither by heaven, neither by the earth, neither by any other oath: but let your yea be yea; and your nay, nay; lest ye fall into condemnation.","ref":"James 5:12","synthesized":"Above all, my brothers, do not swear, not by heaven or earth or by any other oath. Simply let your “Yes” be yes, and your “No,” no, so that you will not fall under judgment.","sources":{"KJV":{"text":"But above all things, my brethren, swear not, neither by heaven, neither by the earth, neither by any other oath: but let your yea be yea; and your nay, nay; lest ye fall into condemnation."},"BSB":{"text":"Above all, my brothers, do not swear, not by heaven or earth or by any other oath. Simply let your “Yes” be yes, and your “No,” no, so that you will not fall under judgment."}},"definableWords":["heaven","or","earth","judgment"],"peopleInVerse":[]},"13":{"text":"Is any among you afflicted? let him pray. Is any merry? let him sing psalms.","ref":"James 5:13","synthesized":"Is any one of you suffering? He should pray. Is anyone cheerful? He should sing praises.","sources":{"KJV":{"text":"Is any among you afflicted? let him pray. Is any merry? let him sing psalms."},"BSB":{"text":"Is any one of you suffering? He should pray. Is anyone cheerful? He should sing praises."}},"definableWords":["one"],"peopleInVerse":[]},"14":{"text":"Is any sick among you? let him call for the elders of the church; and let them pray over him, anointing him with oil in the name of the Lord:","ref":"James 5:14","synthesized":"Is any one of you sick? He should call the elders of the church to pray over him and anoint him with oil in the name of the Lord.","sources":{"KJV":{"text":"Is any sick among you? let him call for the elders of the church; and let them pray over him, anointing him with oil in the name of the Lord:"},"BSB":{"text":"Is any one of you sick? He should call the elders of the church to pray over him and anoint him with oil in the name of the Lord."}},"definableWords":["one","church","anoint","name","Lord"],"peopleInVerse":[]},"15":{"text":"And the prayer of faith shall save the sick, and the Lord shall raise him up; and if he have committed sins, they shall be forgiven him.","ref":"James 5:15","synthesized":"And the prayer offered in faith will restore the one who is sick. The Lord will raise him up. If he has sinned, he will be forgiven.","sources":{"KJV":{"text":"And the prayer of faith shall save the sick, and the Lord shall raise him up; and if he have committed sins, they shall be forgiven him."},"BSB":{"text":"And the prayer offered in faith will restore the one who is sick. The Lord will raise him up. If he has sinned, he will be forgiven."}},"definableWords":["prayer","faith","one","Lord"],"peopleInVerse":[]},"16":{"text":"Confess your faults one to another, and pray one for another, that ye may be healed. The effectual fervent prayer of a righteous man availeth much.","ref":"James 5:16","synthesized":"Therefore confess your sins to each other and pray for each other so that you may be healed. The prayer of a righteous man has great power to prevail.","sources":{"KJV":{"text":"Confess your faults one to another, and pray one for another, that ye may be healed. The effectual fervent prayer of a righteous man availeth much."},"BSB":{"text":"Therefore confess your sins to each other and pray for each other so that you may be healed. The prayer of a righteous man has great power to prevail."}},"definableWords":["prayer","righteous","man","great"],"peopleInVerse":[]},"17":{"text":"Elias was a man subject to like passions as we are, and he prayed earnestly that it might not rain: and it rained not on the earth by the space of three years and six months.","ref":"James 5:17","synthesized":"Elijah was a man just like us. He prayed earnestly that it would not rain, and it did not rain on the land for three and a half years.","sources":{"KJV":{"text":"Elias was a man subject to like passions as we are, and he prayed earnestly that it might not rain: and it rained not on the earth by the space of three years and six months."},"BSB":{"text":"Elijah was a man just like us. He prayed earnestly that it would not rain, and it did not rain on the land for three and a half years."}},"definableWords":["man","land","years"],"peopleInVerse":["Elijah"]},"18":{"text":"And he prayed again, and the heaven gave rain, and the earth brought forth her fruit.","ref":"James 5:18","synthesized":"Again he prayed, and the heavens gave rain, and the earth yielded its crops.","sources":{"KJV":{"text":"And he prayed again, and the heaven gave rain, and the earth brought forth her fruit."},"BSB":{"text":"Again he prayed, and the heavens gave rain, and the earth yielded its crops."}},"definableWords":["heavens","earth"],"peopleInVerse":[]},"19":{"text":"Brethren, if any of you do err from the truth, and one convert him;","ref":"James 5:19","synthesized":"My brothers, if one of you should wander from the truth and someone should bring him back,","sources":{"KJV":{"text":"Brethren, if any of you do err from the truth, and one convert him;"},"BSB":{"text":"My brothers, if one of you should wander from the truth and someone should bring him back,"}},"definableWords":["one","truth"],"peopleInVerse":[]},"20":{"text":"Let him know, that he which converteth the sinner from the error of his way shall save a soul from death, and shall hide a multitude of sins.","ref":"James 5:20","synthesized":"consider this: Whoever turns a sinner from the error of his way will save his soul from death and cover over a multitude of sins.","sources":{"KJV":{"text":"Let him know, that he which converteth the sinner from the error of his way shall save a soul from death, and shall hide a multitude of sins."},"BSB":{"text":"consider this: Whoever turns a sinner from the error of his way will save his soul from death and cover over a multitude of sins."}},"definableWords":["way","soul","death"],"peopleInVerse":[]}}}};